"use client";
import React from 'react';
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Button } from "./ui/button";
import { Input } from "./ui/input";
import { Textarea } from "./ui/textarea";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "./ui/form";
import '../styles/posttask.css';

function PostTask({ currentUser }) {
  const FormSchema = z.object({
    title: z.string().min(1, "Title is required"),
    description: z.string().min(1, "Description is required"),
    tags: z.string().optional(),
    budget: z.string().min(1, "Budget is required"),
    deadline: z.string().min(1, "A deadline is required.")
  });

  const form = useForm({
    resolver: zodResolver(FormSchema),
    defaultValues: {
      title: '',
      description: '',
      tags: '',
      budget: '',
      deadline: ''
    },
  });
  const [success, setSuccess] = React.useState(false);

  async function onSubmit(data) {
    setSuccess(false);
    await fetch('http://localhost:8080/api/tasks', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        ...data,
        poster: { id: currentUser.id }
      })
    });
    setSuccess(true);
    form.reset();
  }

  return (
    <div className="posttask-container">
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)} className="posttask-form">
          <h2 className="posttask-title">Post a Task</h2>
          {success && <div className="posttask-success">Task posted!</div>}

          <FormField
            control={form.control}
            name="title"
            render={({ field }) => (
              <FormItem className="posttask-formitem">
                <FormLabel className="posttask-label">Title</FormLabel>
                <FormControl>
                  <Input className="posttask-input" placeholder="Title" {...field} />
                </FormControl>
                <FormMessage className="posttask-formmsg" />
              </FormItem>
            )}
          />
          <FormField
            control={form.control}
            name="description"
            render={({ field }) => (
              <FormItem className="posttask-formitem">
                <FormLabel className="posttask-label">Description</FormLabel>
                <FormControl>
                  <Textarea className="posttask-textarea" placeholder="Describe your task" {...field} />
                </FormControl>
                <FormMessage className="posttask-formmsg" />
              </FormItem>
            )}
          />
          <FormField
            control={form.control}
            name="tags"
            render={({ field }) => (
              <FormItem className="posttask-formitem">
                <FormLabel className="posttask-label">Tags</FormLabel>
                <FormControl>
                  <Input className="posttask-input" placeholder="Tags (comma separated)" {...field} />
                </FormControl>
                <FormMessage className="posttask-formmsg" />
              </FormItem>
            )}
          />
          <FormField
            control={form.control}
            name="budget"
            render={({ field }) => (
              <FormItem className="posttask-formitem">
                <FormLabel className="posttask-label">Budget (₹)</FormLabel>
                <FormControl>
                  <Input className="posttask-input" type="number" placeholder="Budget (₹)" {...field} />
                </FormControl>
                <FormMessage className="posttask-formmsg" />
              </FormItem>
            )}
          />
          <FormField
            control={form.control}
            name="deadline"
            render={({ field }) => (
              <FormItem className="posttask-formitem">
                <FormLabel className="posttask-label">Deadline</FormLabel>
                <FormControl>
                  <Input className="posttask-input" type="date" placeholder="Deadline" {...field} />
                </FormControl>
                <FormDescription className="posttask-formdesc">
                  The deadline for your task.
                </FormDescription>
                <FormMessage className="posttask-formmsg" />
              </FormItem>
            )}
          />
          <Button className="posttask-btn" type="submit">Post Task</Button>
        </form>
      </Form>
    </div>
  );
}

export default PostTask;
